const { ethers } = require('ethers');

// Wallet and Provider setup
const privateKey = 'your-private-key';
const providerURL = 'https://mainnet.infura.io/v3/your-infura-project-id';

const provider = new ethers.providers.JsonRpcProvider(providerURL);
const wallet = new ethers.Wallet(privateKey, provider);

// Function to send ETH
async function sendETH(toAddress, amountInEther) {
  const tx = {
    to: toAddress,
    value: ethers.utils.parseEther(amountInEther)
  };

  try {
    const transactionResponse = await wallet.sendTransaction(tx);
    await transactionResponse.wait();
    console.log(`Transaction successful with hash: ${transactionResponse.hash}`);
  } catch (error) {
    console.error(`Failed to send ETH: ${error.message}`);
  }
}

// Function to interact with a smart contract
async function interactWithContract(contractAddress, abi, functionName, args = []) {
  const contract = new ethers.Contract(contractAddress, abi, wallet);

  try {
    const result = await contract[functionName](...args);
    console.log(`Contract interaction successful: ${result}`);
  } catch (error) {
    console.error(`Failed to interact with contract: ${error.message}`);
  }
}

